/**
 * Island Loader — discovers data-island markers and loads Wasm modules.
 *
 * Architecture:
 * 1. On DOMContentLoaded, scans for [data-island]:not([data-island-hydrated])
 * 2. Loads /static/wasm/{name}/main.bc.wasm.js (JS glue generated by wasm_of_ocaml)
 * 3. Marks hydrated elements with data-island-hydrated="true"
 * 4. On htmx:afterSwap, re-scans the swapped subtree for new islands
 *
 * Fallback: if WebAssembly is unavailable, logs a warning and does nothing.
 * Individual islands can provide JS fallbacks via data-island-fallback="path.js".
 */
(function () {
  'use strict';

  var loaded = {};

  function loadScript(src) {
    if (loaded[src]) return loaded[src];
    loaded[src] = new Promise(function (resolve, reject) {
      var s = document.createElement('script');
      s.src = src;
      s.onload = resolve;
      s.onerror = function () {
        delete loaded[src];
        reject(new Error('Failed to load island: ' + src));
      };
      document.head.appendChild(s);
    });
    return loaded[src];
  }

  function hydrateSubtree(root) {
    if (typeof WebAssembly !== 'object') {
      console.warn('[island-loader] WebAssembly not available');
      return;
    }

    var islands = (root || document).querySelectorAll(
      '[data-island]:not([data-island-hydrated])'
    );

    var names = {};
    for (var i = 0; i < islands.length; i++) {
      var name = islands[i].getAttribute('data-island');
      if (name) names[name] = true;
    }

    Object.keys(names).forEach(function (name) {
      var src = '/static/wasm/' + name + '/main.bc.wasm.js';
      loadScript(src).catch(function (err) {
        console.warn('[island-loader] ' + err.message);
        // Try JS fallback if specified
        var el = document.querySelector('[data-island="' + name + '"][data-island-fallback]');
        if (el) {
          var fallback = el.getAttribute('data-island-fallback');
          if (fallback) {
            loadScript(fallback).catch(function (e2) {
              console.warn('[island-loader] fallback also failed: ' + e2.message);
            });
          }
        }
      });
    });
  }

  function init() {
    hydrateSubtree(document);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

  // Re-hydrate after HTMX content swap
  document.body.addEventListener('htmx:afterSwap', function (e) {
    hydrateSubtree(e.detail.target);
  });

  window.IslandLoader = { hydrate: hydrateSubtree };
})();
